module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] quotient;
    reg [15:0] remainder;

    always @(A, B) begin
        dividend <= A;
        divisor <= B;
    end

    always @(dividend, divisor) begin
        quotient <= 0;
        remainder <= 0;

        for (int i = 15; i >= 0; i--) begin
            remainder <= {remainder[14:0], dividend[i]};
            if (remainder >= divisor) begin
                remainder <= remainder - divisor;
                quotient[i] <= 1'b1;
            end
        end

        result <= quotient;
        odd <= remainder;
    end

endmodule
